#[kani::proof]
#[kani::unwind(2)]
#[kani::solver(cadical)]
fn verify_deposit_effects() {
    let mut s = State {
        V: kani::any(),
        C_tot: kani::any(),
        I: kani::any(),
    };
    let amount: u128 = kani::any();
    let pre_V = s.V;
    let pre_C_tot = s.C_tot;
    let pre_I = s.I;
    if deposit(&mut s, amount) {
        assert!(s.V == pre_V + amount, "V must increment by amount");
        assert!(s.C_tot == pre_C_tot + amount, "C_tot must increment by amount");
        assert!(s.I == pre_I, "I must not change");
    }
}

#[kani::proof]
#[kani::unwind(2)]
#[kani::solver(cadical)]
fn verify_withdraw_effects() {
    let mut s = State {
        V: kani::any(),
        C_tot: kani::any(),
        I: kani::any(),
    };
    let amount: u128 = kani::any();
    let pre_V = s.V;
    let pre_C_tot = s.C_tot;
    let pre_I = s.I;
    if withdraw(&mut s, amount) {
        assert!(s.V == pre_V - amount, "V must decrement by amount");
        assert!(s.C_tot == pre_C_tot - amount, "C_tot must decrement by amount");
        assert!(s.I == pre_I, "I must not change");
    }
}

