#[kani::proof]
#[kani::unwind(3)]
#[kani::solver(cadical)]
fn verify_liveness_drain_completes() {
    let mut s = State {
        V: kani::any(),
        C_tot: kani::any(),
        I: kani::any(),
    };
    for _ in 0..2 {
        let op: u8 = kani::any();
        match op {
            0 => {
                complete_drain(&mut s);
            }
            1 => {
                reset(&mut s);
            }
            _ => {}
        }
    }
    // Target: from Draining to Active within 2 steps
}

